// Validate Auth Token - Extract and verify API key or JWT
const authHeader = $input.item.json.headers?.authorization || $input.item.json.headers?.Authorization;

if (!authHeader) {
  return [{
    json: {
      valid: false,
      user_id: null,
      error: 'Missing Authorization header'
    }
  }];
}

// Extract token (support both "Bearer TOKEN" and plain token)
const token = authHeader.startsWith('Bearer ') 
  ? authHeader.substring(7) 
  : authHeader;

if (!token || token.trim() === '') {
  return [{
    json: {
      valid: false,
      user_id: null,
      error: 'Empty authorization token'
    }
  }];
}

// Simple API key validation (format: nexourz_userid_randomstring)
// Example: nexourz_user123_abc456def789
if (token.startsWith('nexourz_')) {
  const parts = token.split('_');

  if (parts.length >= 3) {
    const user_id = parts[1];

    // Basic validation: user_id should not be empty
    if (user_id && user_id.length > 0) {
      return [{
        json: {
          valid: true,
          user_id: user_id,
          error: null
        }
      }];
    }
  }

  return [{
    json: {
      valid: false,
      user_id: null,
      error: 'Invalid API key format'
    }
  }];
}

// JWT validation (basic decode - for production use proper JWT library)
try {
  const parts = token.split('.');

  if (parts.length === 3) {
    // Decode JWT payload (base64url)
    const payload = JSON.parse(
      Buffer.from(parts[1].replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString()
    );

    // Check expiration
    if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
      return [{
        json: {
          valid: false,
          user_id: null,
          error: 'Token expired'
        }
      }];
    }

    // Extract user_id from payload
    const user_id = payload.user_id || payload.sub || payload.userId;

    if (user_id) {
      return [{
        json: {
          valid: true,
          user_id: user_id,
          error: null
        }
      }];
    }

    return [{
      json: {
        valid: false,
        user_id: null,
        error: 'No user_id found in token'
      }
    }];
  }
} catch (e) {
  // Not a valid JWT, continue to fallback
}

// If we reach here, token format is not recognized
return [{
  json: {
    valid: false,
    user_id: null,
    error: 'Invalid token format - expected API key (nexourz_*) or JWT'
  }
}];

// Calculate Stats from Post Log data
const items = $input.all();

// Count posts by status
const posts_sent = items.length;
const success_count = items.filter(item => item.json.status === 'success').length;
const failed_count = items.filter(item => item.json.status === 'error').length;

// Placeholder engagement rate calculation
// In production, this would calculate based on likes/comments/shares
const engagement_rate = success_count > 0 ? ((success_count / posts_sent) * 100).toFixed(2) : 0;

// Return single object with stats
return [{
  json: {
    posts_sent: posts_sent,
    success_count: success_count,
    failed_count: failed_count,
    engagement_rate: parseFloat(engagement_rate)
  }
}];

// Validate User Ownership - Check if authenticated user owns the page_id being configured
const authenticatedUserId = $('Validate Auth Token').item.json.user_id;
const requestedPageId = $input.item.json.body?.page_id;

if (!requestedPageId) {
  return [{
    json: {
      valid: false,
      error: 'Missing page_id in request body'
    }
  }];
}

// Query Accounts_Config table to find matching page_id
// Note: In production, this would use a proper database query node
// For now, we'll use a placeholder that assumes the data is available
try {
  // This is a placeholder - in the actual workflow, you would:
  // 1. Add a Data Table or Google Sheets node before this
  // 2. Query Accounts_Config where page_id = requestedPageId
  // 3. Check if the returned user_id matches authenticatedUserId

  // For now, return a structure that expects the query result
  // The actual implementation would check:
  // const accountConfig = $('Query Account Config').item.json;
  // if (accountConfig && accountConfig.user_id === authenticatedUserId)

  return [{
    json: {
      valid: true,
      error: null,
      page_id: requestedPageId,
      user_id: authenticatedUserId
    }
  }];

} catch (error) {
  return [{
    json: {
      valid: false,
      error: `Validation error: ${error.message}`
    }
  }];
}

const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
return [{
  json: {
    threshold_24h: twentyFourHoursAgo,
    current_time: new Date().toISOString()
  }
}];

const errorMsg = $input.item.json.error_message || '';
let category = 'other';
let is_retryable = false;

if (errorMsg.match(/token|expired|invalid.*token|OAuthException/i)) {
  category = 'token_error';
  is_retryable = false;
} else if (errorMsg.match(/rate.*limit|too.*many.*requests|429/i)) {
  category = 'rate_limit';
  is_retryable = true;
} else if (errorMsg.match(/network|timeout|ECONNREFUSED/i)) {
  category = 'network_error';
  is_retryable = true;
}

return [{
  json: {
    ...$input.item.json,
    error_category: category,
    is_retryable: is_retryable
  }
}];

