// Compute per-user metrics from merged Post_Log and Engagement_Log data
const items = $input.all();

// Separate Post_Log and Engagement_Log items
const postLogs = items.filter(item => item.json.status !== undefined);
const engagementLogs = items.filter(item => item.json.engagement_type !== undefined);

// Group posts by user_id
const userMetrics = {};

postLogs.forEach(post => {
  const userId = post.json.user_id || 'unknown';

  if (!userMetrics[userId]) {
    userMetrics[userId] = {
      user_id: userId,
      total_posts: 0,
      successful_posts: 0,
      failed_posts: 0,
      total_delay_minutes: 0,
      delay_count: 0,
      total_engagements: 0
    };
  }

  userMetrics[userId].total_posts++;

  if (post.json.status === 'success') {
    userMetrics[userId].successful_posts++;
  } else if (post.json.status === 'error') {
    userMetrics[userId].failed_posts++;
  }

  // Track delay minutes if available
  const delayMinutes = parseFloat(post.json.delay_minutes);
  if (!isNaN(delayMinutes)) {
    userMetrics[userId].total_delay_minutes += delayMinutes;
    userMetrics[userId].delay_count++;
  }
});

// Count engagements per user (likes + comments)
engagementLogs.forEach(engagement => {
  const userId = engagement.json.user_id || 'unknown';

  if (userMetrics[userId]) {
    userMetrics[userId].total_engagements++;
  }
});

// Calculate final metrics for each user
const userResults = [];
let totalEngagementRate = 0;
let totalAvgDelay = 0;
let userCount = 0;

for (const userId in userMetrics) {
  const metrics = userMetrics[userId];

  // Calculate average delay used
  const avg_delay_used = metrics.delay_count > 0 
    ? (metrics.total_delay_minutes / metrics.delay_count).toFixed(2) 
    : 0;

  // Calculate engagement rate: (total_engagements / total_posts) * 100
  const engagement_rate = metrics.total_posts > 0 
    ? ((metrics.total_engagements / metrics.total_posts) * 100).toFixed(2) 
    : 0;

  userResults.push({
    user_id: userId,
    total_posts: metrics.total_posts,
    successful_posts: metrics.successful_posts,
    failed_posts: metrics.failed_posts,
    avg_delay_used: parseFloat(avg_delay_used),
    total_engagements: metrics.total_engagements,
    engagement_rate: parseFloat(engagement_rate)
  });

  totalEngagementRate += parseFloat(engagement_rate);
  totalAvgDelay += parseFloat(avg_delay_used);
  userCount++;
}

// Calculate overall averages
const overall_avg_engagement_rate = userCount > 0 
  ? (totalEngagementRate / userCount).toFixed(2) 
  : 0;

const overall_avg_delay = userCount > 0 
  ? (totalAvgDelay / userCount).toFixed(2) 
  : 0;

// Add overall metrics to each user for comparison
const finalResults = userResults.map(user => ({
  ...user,
  overall_avg_engagement_rate: parseFloat(overall_avg_engagement_rate),
  overall_avg_delay: parseFloat(overall_avg_delay),
  engagement_vs_avg: (user.engagement_rate - parseFloat(overall_avg_engagement_rate)).toFixed(2)
}));

return finalResults.map(result => ({ json: result }));

// Generate Chart.js configuration data for analytics report
const items = $input.all();

// Extract user metrics from input
const userMetrics = items.map(item => item.json);

// Sort users by total_posts for better visualization
userMetrics.sort((a, b) => b.total_posts - a.total_posts);

// 1. Bar Chart: Posts per User
const postsBarChart = {
  type: 'bar',
  data: {
    labels: userMetrics.map(u => u.user_id),
    datasets: [
      {
        label: 'Total Posts',
        data: userMetrics.map(u => u.total_posts),
        backgroundColor: 'rgba(54, 162, 235, 0.6)',
        borderColor: 'rgba(54, 162, 235, 1)',
        borderWidth: 1
      },
      {
        label: 'Successful Posts',
        data: userMetrics.map(u => u.successful_posts),
        backgroundColor: 'rgba(75, 192, 192, 0.6)',
        borderColor: 'rgba(75, 192, 192, 1)',
        borderWidth: 1
      },
      {
        label: 'Failed Posts',
        data: userMetrics.map(u => u.failed_posts),
        backgroundColor: 'rgba(255, 99, 132, 0.6)',
        borderColor: 'rgba(255, 99, 132, 1)',
        borderWidth: 1
      }
    ]
  },
  options: {
    responsive: true,
    plugins: {
      title: {
        display: true,
        text: 'Posts per User (Total, Success, Failed)'
      },
      legend: {
        display: true,
        position: 'top'
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        title: {
          display: true,
          text: 'Number of Posts'
        }
      },
      x: {
        title: {
          display: true,
          text: 'User ID'
        }
      }
    }
  }
};

// 2. Line Chart: Engagement Rate Comparison
const engagementLineChart = {
  type: 'line',
  data: {
    labels: userMetrics.map(u => u.user_id),
    datasets: [
      {
        label: 'User Engagement Rate (%)',
        data: userMetrics.map(u => u.engagement_rate),
        borderColor: 'rgba(255, 159, 64, 1)',
        backgroundColor: 'rgba(255, 159, 64, 0.2)',
        fill: true,
        tension: 0.4
      },
      {
        label: 'Platform Average (%)',
        data: userMetrics.map(u => u.overall_avg_engagement_rate),
        borderColor: 'rgba(153, 102, 255, 1)',
        backgroundColor: 'rgba(153, 102, 255, 0.2)',
        fill: false,
        borderDash: [5, 5],
        tension: 0.4
      }
    ]
  },
  options: {
    responsive: true,
    plugins: {
      title: {
        display: true,
        text: 'Engagement Rate: User vs Platform Average'
      },
      legend: {
        display: true,
        position: 'top'
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        title: {
          display: true,
          text: 'Engagement Rate (%)'
        }
      },
      x: {
        title: {
          display: true,
          text: 'User ID'
        }
      }
    }
  }
};

// 3. Doughnut Chart: Overall Success vs Failed Posts
const totalSuccess = userMetrics.reduce((sum, u) => sum + u.successful_posts, 0);
const totalFailed = userMetrics.reduce((sum, u) => sum + u.failed_posts, 0);

const successDoughnutChart = {
  type: 'doughnut',
  data: {
    labels: ['Successful Posts', 'Failed Posts'],
    datasets: [
      {
        data: [totalSuccess, totalFailed],
        backgroundColor: [
          'rgba(75, 192, 192, 0.8)',
          'rgba(255, 99, 132, 0.8)'
        ],
        borderColor: [
          'rgba(75, 192, 192, 1)',
          'rgba(255, 99, 132, 1)'
        ],
        borderWidth: 2
      }
    ]
  },
  options: {
    responsive: true,
    plugins: {
      title: {
        display: true,
        text: 'Overall Post Success Rate'
      },
      legend: {
        display: true,
        position: 'bottom'
      }
    }
  }
};

// Return chart configurations as JSON
return [{
  json: {
    charts: {
      postsBarChart: postsBarChart,
      engagementLineChart: engagementLineChart,
      successDoughnutChart: successDoughnutChart
    },
    chartConfigs: {
      postsBarChartJson: JSON.stringify(postsBarChart),
      engagementLineChartJson: JSON.stringify(engagementLineChart),
      successDoughnutChartJson: JSON.stringify(successDoughnutChart)
    },
    summary: {
      total_users: userMetrics.length,
      total_posts: userMetrics.reduce((sum, u) => sum + u.total_posts, 0),
      total_success: totalSuccess,
      total_failed: totalFailed,
      success_rate: totalSuccess + totalFailed > 0 ? ((totalSuccess / (totalSuccess + totalFailed)) * 100).toFixed(2) : 0
    }
  }
}];

// Flag Top Performers for Upsell
const items = $input.all();

// Calculate overall average engagement rate
let totalEngagementRate = 0;
let userCount = items.length;

items.forEach(item => {
  totalEngagementRate += item.json.engagement_rate || 0;
});

const avgEngagementRate = userCount > 0 ? totalEngagementRate / userCount : 0;
const upsellThreshold = avgEngagementRate * 1.5;

// Flag users for upsell
const enhancedUsers = items.map(item => {
  const user = item.json;
  const engagementRate = user.engagement_rate || 0;
  const totalPosts = user.total_posts || 0;

  let upsellCandidate = false;
  let upsellReason = '';

  // Check if user qualifies for upsell
  if (engagementRate > upsellThreshold && totalPosts > 50) {
    upsellCandidate = true;
    upsellReason = `High engagement (${engagementRate}% vs ${avgEngagementRate.toFixed(2)}% avg) + High volume (${totalPosts} posts)`;
  } else if (engagementRate > upsellThreshold) {
    upsellCandidate = true;
    upsellReason = `High engagement rate: ${engagementRate}% (${((engagementRate / avgEngagementRate - 1) * 100).toFixed(0)}% above average)`;
  } else if (totalPosts > 50) {
    upsellCandidate = true;
    upsellReason = `Power user: ${totalPosts} posts published`;
  }

  return {
    json: {
      ...user,
      upsell_candidate: upsellCandidate,
      upsell_reason: upsellReason,
      avg_engagement_rate: parseFloat(avgEngagementRate.toFixed(2)),
      upsell_threshold: parseFloat(upsellThreshold.toFixed(2))
    }
  };
});

return enhancedUsers;

